type UseBEM = (
	blockName: string,
) => [string, (modifierName: string) => string, (elementName: string) => ReturnType<UseBEM>];

export const getBEMClasses: UseBEM = (blockName: string) => [
	blockName,
	(modifierName): string => `${blockName}--${modifierName}`,
	(elementName): ReturnType<UseBEM> => getBEMClasses(`${blockName}__${elementName}`),
];
